import type { CardConfig } from "../contracts/types";

export function migrateSavedConfigActionLegacy(config: CardConfig): boolean {
  if (config.type === "local") {
    config.type = "action";
    config.sensor = "local";
    config.unit = "";
    config.precision = "";
    config.options = "";
    config.icon_on = "Auto";
    return true;
  }
  if (config.type === "option_select") {
    config.type = "action";
    config.sensor = "input_select.select_option";
    config.unit = "";
    config.precision = "";
    config.options = "";
    config.icon_on = "Auto";
    return true;
  }
  return false;
}

export type SavedConfigActionFieldHook = (config: CardConfig) => void;
export type SavedConfigActionOptionHook = (options: string, action: string) => string;

export function normalizeSavedConfigAction(
  config: CardConfig,
  normalizeFields: SavedConfigActionFieldHook,
  normalizeOptions: SavedConfigActionOptionHook,
): boolean {
  if (config.type !== "action") return false;
  normalizeFields(config);
  config.options = normalizeOptions(config.options || "", config.sensor || "");
  return true;
}
